const msg = $input.first().json.message;
let fileId = null;
let kind = null;
let mimeHint = 'application/octet-stream';

if (msg.photo && Array.isArray(msg.photo) && msg.photo.length > 0) {
  // Telegram sends multiple sizes; take the largest
  const sorted = [...msg.photo].sort((a, b) => (b.file_size || 0) - (a.file_size || 0));
  fileId = sorted[0].file_id;
  kind = 'photo';
  mimeHint = 'image/jpeg';
} else if (msg.video) {
  fileId = msg.video.file_id;
  kind = 'video';
  mimeHint = msg.video.mime_type || 'video/mp4';
} else if (msg.video_note) {
  fileId = msg.video_note.file_id;
  kind = 'video_note';
  mimeHint = 'video/mp4';
} else if (msg.document) {
  fileId = msg.document.file_id;
  kind = 'document';
  mimeHint = msg.document.mime_type || 'application/octet-stream';
}

// Caption parsing — operator can tag the asset:
//   pillar=ga4-tip role=character shot=0 account=severus
// Defaults if no caption supplied.
const caption = (msg.caption || '').trim();
const tags = {};
caption.split(/\s+/).forEach(token => {
  const [k, v] = token.split('=');
  if (k && v) tags[k.toLowerCase()] = v;
});

const account = tags.account || 'severus';
const pillar = tags.pillar || 'inbox';
const role = tags.role || (kind === 'photo' ? 'character' : 'clip');
const shotIndex = tags.shot !== undefined ? parseInt(tags.shot, 10) : null;
const date = new Date().toISOString().slice(0, 10);
const ts = Date.now();

// Filename: <pillar>_<role>[_shot<N>]_<ts>.<ext>
const extMap = { 'image/jpeg': 'jpg', 'image/png': 'png', 'video/mp4': 'mp4' };
const ext = extMap[mimeHint] || (kind === 'photo' ? 'jpg' : 'mp4');
const shotSuffix = shotIndex !== null ? `_shot${shotIndex}` : '';
const filename = `${pillar}_${role}${shotSuffix}_${ts}.${ext}`;
const relativePath = `severus-social/uploads/${account}/${date}/${filename}`;

return [{
  json: {
    file_id: fileId,
    kind,
    mime: mimeHint,
    filename,
    relativePath,
    account,
    pillar,
    role,
    shotIndex,
    caption,
    chat_id: msg.chat.id,
    message_id: msg.message_id,
    from_username: msg.from?.username || 'unknown',
  },
}];

const meta = $('Parse caption tags + plan path').first().json;
const entry = {
  ts: new Date().toISOString(),
  account: meta.account,
  pillar: meta.pillar,
  role: meta.role,
  shotIndex: meta.shotIndex,
  kind: meta.kind,
  mime: meta.mime,
  filename: meta.filename,
  relativePath: meta.relativePath,
  caption: meta.caption,
  from: meta.from_username,
  telegram_message_id: meta.message_id,
};
return [{ json: { ...meta, manifestLine: JSON.stringify(entry) + '\n' } }];

